"use client";

import { useLocale, useTranslations } from "next-intl";
import { Link, usePathname } from "@/i18n/navigation";
import { routing, type Locale } from "@/i18n/routing";

/**
 * Sélecteur de langue.
 *
 * - `usePathname()` (next-intl) renvoie le chemin SANS préfixe de locale,
 *   donc on peut régénérer le même chemin dans une autre langue.
 * - `<Link href={pathname} locale="en">` génère le bon préfixe (/en/...)
 *   ou la racine pour le français (localePrefix "as-needed").
 * - Rendu en vraies balises <a> → crawlable, fonctionne sans JS.
 */
const SHORT: Record<Locale, string> = { fr: "FR", en: "EN", es: "ES" };

export default function LocaleSwitcher({
  className = "",
}: {
  className?: string;
}) {
  const pathname = usePathname();
  const active = useLocale();
  const t = useTranslations("localeSwitcher");

  return (
    <nav
      aria-label={t("label")}
      className={`flex items-center gap-0.5 rounded-lg border border-white/[.08] bg-white/[.02] p-0.5 ${className}`}
    >
      {routing.locales.map((loc) => {
        const isActive = loc === active;
        return (
          <Link
            key={loc}
            href={pathname}
            locale={loc}
            hrefLang={loc}
            aria-current={isActive ? "true" : undefined}
            className={`rounded-md px-2 py-1 text-xs font-semibold uppercase tracking-wide transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-violet-400 ${
              isActive
                ? "bg-violet-500/15 text-violet-300"
                : "text-slate-400 hover:bg-white/[.05] hover:text-white"
            }`}
          >
            {SHORT[loc]}
          </Link>
        );
      })}
    </nav>
  );
}
